<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Snake</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    user-select: none;
  }
  .game-container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
  }
  #score {
    font-size: 28px;
    font-weight: bold;
    color: #0f3460;
    background: #e94560;
    padding: 8px 24px;
    border-radius: 8px;
    letter-spacing: 1px;
  }
  canvas {
    display: block;
    border: 3px solid #16213e;
    border-radius: 4px;
    background: #0f3460;
  }
  .controls {
    display: flex;
    gap: 12px;
  }
  button {
    padding: 10px 24px;
    font-size: 15px;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: bold;
    transition: transform 0.1s, opacity 0.15s;
  }
  button:active { transform: scale(0.95); }
  #start { background: #e94560; color: white; }
  #pause { background: #16213e; color: #eee; border: 1px solid #533483; }
  #reset { background: #533483; color: white; }
</style>
</head>
<body>

<div class="game-container">
  <div id="score">Score: 0</div>
  <canvas id="snake" width="400" height="400"></canvas>
  <div class="controls">
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
  </div>
</div>

<script>
(function () {
  'use strict';

  const W = 20, H = 20; // board size in cells (>=10)
  const CELL = Math.floor(400 / W); // cell pixel size
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');

  // Internal state
  let snake, dir, nextDir, food, alive, score, running, paused;

  function init() {
    snake = [
      [10, 10],
      [9, 10],
      [8, 10]
    ];
    dir = 'right';
    nextDir = 'right';
    food = null;
    alive = true;
    score = 0;
    running = false;
    paused = false;
    placeFood();
    draw();
    updateScore();
  }

  function placeFood() {
    const occupied = new Set(snake.map(s => s[0] + ',' + s[1]));
    let x, y, attempts = 0;
    do {
      x = Math.floor(Math.random() * W);
      y = Math.floor(Math.random() * H);
      attempts++;
    } while (occupied.has(x + ',' + y) && attempts < 500);
    food = [x, y];
  }

  function draw() {
    // Background
    ctx.fillStyle = '#16213e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid lines (subtle)
    ctx.strokeStyle = 'rgba(255,255,255,0.04)';
    ctx.lineWidth = 0.5;
    for (let i = 1; i < W; i++) {
      ctx.beginPath();
      ctx.moveTo(i * CELL, 0);
      ctx.lineTo(i * CELL, H * CELL);
      ctx.stroke();
    }
    for (let j = 1; j < H; j++) {
      ctx.beginPath();
      ctx.moveTo(0, j * CELL);
      ctx.lineTo(W * CELL, j * CELL);
      ctx.stroke();
    }

    // Food
    if (food) {
      const fx = food[0] * CELL + CELL / 2;
      const fy = food[1] * CELL + CELL / 2;
      ctx.fillStyle = '#e94560';
      ctx.shadowColor = '#e94560';
      ctx.shadowBlur = 8;
      ctx.beginPath();
      ctx.arc(fx, fy, CELL * 0.38, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Food highlight
      ctx.fillStyle = 'rgba(255,255,255,0.3)';
      ctx.beginPath();
      ctx.arc(fx - CELL * 0.1, fy - CELL * 0.1, CELL * 0.12, 0, Math.PI * 2);
      ctx.fill();
    }

    // Snake
    snake.forEach((seg, i) => {
      const x = seg[0] * CELL;
      const y = seg[1] * CELL;
      if (i === 0) {
        // Head
        ctx.fillStyle = '#533483';
        ctx.shadowColor = '#533483';
        ctx.shadowBlur = 6;
      } else {
        const ratio = i / snake.length;
        ctx.fillStyle = `hsl(${200 + ratio * 40}, 70%, ${50 - ratio * 15}%)`;
        ctx.shadowColor = 'transparent';
      }
      const pad = CELL > 6 ? 1 : 0;
      roundRect(ctx, x + pad, y + pad, CELL - pad * 2, CELL - pad * 2);
      ctx.fill();

      // Eyes on head
      if (i === 0) {
        ctx.fillStyle = '#fff';
        const ex1 = seg[0] * CELL + CELL / 2;
        const ey1 = seg[1] * CELL + CELL / 2;
        let e1x, e1y, e2x, e2y;
        if (dir === 'up') { e1x = ex1 - 3; e1y = ey1 - 4; e2x = ex1 + 3; e2y = ey1 - 4; }
        else if (dir === 'down') { e1x = ex1 - 3; e1y = ey1 + 4; e2x = ex1 + 3; e2y = ey1 + 4; }
        else if (dir === 'left') { e1x = ex1 - 5; e1y = ey1 - 3; e2x = ex1 - 5; e2y = ey1 + 3; }
        else { e1x = ex1 + 4; e1y = ey1 - 3; e2x = ex1 + 4; e2y = ey1 + 3; }
        ctx.beginPath(); ctx.arc(e1x, e1y, 2.5, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.arc(e2x, e2y, 2.5, 0, Math.PI * 2); ctx.fill();
      }

      ctx.shadowBlur = 0;
    });

    // Game over overlay
    if (!alive) {
      ctx.fillStyle = 'rgba(15, 52, 96, 0.75)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#e94560';
      ctx.font = 'bold 32px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('GAME OVER', W * CELL / 2, H * CELL / 2 - 10);
      ctx.font = '18px sans-serif';
      ctx.fillStyle = '#eee';
      ctx.fillText(`Score: ${score}`, W * CELL / 2, H * CELL / 2 + 24);
    }

    // Paused overlay
    if (paused) {
      ctx.fillStyle = 'rgba(15, 52, 96, 0.5)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#e94560';
      ctx.font = 'bold 28px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('PAUSED', W * CELL / 2, H * CELL / 2);
    }

    // Running indicator
    if (running && alive) {
      ctx.fillStyle = '#533483';
      ctx.font = '16px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('●', W * CELL / 2, H * CELL + 10);
    }
  }

  function roundRect(ctx, x, y, w, h) {
    const r = Math.min(w, h) * 0.2;
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function updateScore() {
    scoreEl.textContent = 'Score: ' + score;
  }

  // --- Public API (window.game) ---

  window.game = {
    w: W,
    h: H,

    reset: function () { init(); },

    tick: function () {
      if (!alive || paused) return;
      applyDir();
      const head = snake[0];
      const nx = head[0] + dirX[dir];
      const ny = head[1] + dirY[dir];

      // Wall collision
      if (nx < 0 || nx >= W || ny < 0 || ny >= H) {
        alive = false;
        running = false;
        draw();
        return;
      }

      // Self collision
      for (let i = 0; i < snake.length; i++) {
        if (snake[i][0] === nx && snake[i][1] === ny) {
          alive = false;
          running = false;
          draw();
          return;
        }
      }

      // Move
      const newHead = [nx, ny];
      snake.unshift(newHead);

      // Eat food?
      if (food && nx === food[0] && ny === food[1]) {
        score++;
        updateScore();
        placeFood();
      } else {
        snake.pop();
      }

      draw();
    },

    setDir: function (d) {
      const opposites = { up: 'down', down: 'up', left: 'right', right: 'left' };
      if (!opposites[d] || d === dir) return; // ignore 180° reversals and repeats
      nextDir = d;
    },

    setFood: function (x, y) {
      food = [x, y];
      draw();
    },

    snake: function () {
      return snake.map(s => [s[0], s[1]]);
    },

    food: function () {
      return food ? [food[0], food[1]] : null;
    },

    alive: function () {
      return alive;
    },

    score: function () {
      return score;
    }
  };

  // Direction helpers
  const dirX = { up: 0, down: 0, left: -1, right: 1 };
  const dirY = { up: -1, down: 1, left: 0, right: 0 };

  function applyDir() {
    if (dir !== nextDir) {
      dir = nextDir;
    }
  }

  // --- Input handling ---

  document.addEventListener('keydown', e => {
    const map = {
      ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right'
    };
    if (map[e.key]) {
      window.game.setDir(map[e.key]);
      e.preventDefault();
    }
  });

  // --- Button handlers ---

  document.getElementById('start').addEventListener('click', () => {
    if (!alive) return;
    running = true;
    paused = false;
    gameLoop();
  });

  document.getElementById('pause').addEventListener('click', () => {
    if (paused || !running) return;
    paused = true;
    draw();
  });

  document.getElementById('reset').addEventListener('click', () => {
    init();
  });

  // --- Game loop ---

  let lastTick = 0;
  const TICK_MS = 120;

  function gameLoop(timestamp) {
    if (!running || paused) return;
    if (timestamp - lastTick >= TICK_MS) {
      window.game.tick();
      lastTick = timestamp;
    }
    requestAnimationFrame(gameLoop);
  }

  // --- Initial draw ---
  init();
})();
</script>
</body>
</html>
